import asyncio
import re
import json
from typing import Dict, List, Optional, Tuple, Any
from dataclasses import dataclass, asdict
from enum import Enum
from datetime import datetime
import hashlib

from .config import Config

class OptimizationType(Enum):
    """Types of pre-RAG optimizations"""
    CONTEXT_COMPRESSION = "context_compression"
    SEMANTIC_CHUNKING = "semantic_chunking"
    QUERY_ENHANCEMENT = "query_enhancement"
    RELEVANCE_FILTERING = "relevance_filtering"
    PROMPT_OPTIMIZATION = "prompt_optimization"

class ContentType(Enum):
    """Types of content for optimization"""
    CODE = "code"
    DOCUMENTATION = "documentation"
    CONVERSATION = "conversation"
    SYSTEM_OUTPUT = "system_output"
    USER_QUERY = "user_query"

@dataclass
class OptimizationResult:
    """Result of pre-RAG optimization"""
    original_content: str
    optimized_content: str
    optimization_type: OptimizationType
    compression_ratio: float = 0.0
    quality_score: float = 0.0
    metadata: Dict[str, Any] = None
    processing_time: float = 0.0

    def __post_init__(self):
        if self.metadata is None:
            self.metadata = {}

@dataclass
class SemanticChunk:
    """Semantically coherent chunk of content"""
    content: str
    chunk_type: ContentType
    importance_score: float = 0.0
    context_dependencies: List[str] = None
    semantic_tags: List[str] = None
    token_estimate: int = 0

    def __post_init__(self):
        if self.context_dependencies is None:
            self.context_dependencies = []
        if self.semantic_tags is None:
            self.semantic_tags = []

class PreRAGOptimizer:
    """Advanced pre-RAG optimization system with EdgeInfinite-inspired techniques"""

    def __init__(self, config: Config):
        self.config = config

        # Optimization weights based on research
        self.optimization_weights = {
            'semantic_coherence': 0.35,
            'information_density': 0.25,
            'context_relevance': 0.20,
            'token_efficiency': 0.20
        }

        # Pattern libraries for different content types
        self.code_patterns = {
            'function_definitions': r'(?:def|function|class)\s+\w+.*?(?=\n(?:def|class|\Z))',
            'imports': r'(?:import|from)\s+[\w\.]+.*?\n',
            'comments': r'#.*?$|\/\/.*?$|\/\*.*?\*\/',
            'docstrings': r'""".*?"""|\'\'\'.*?\'\'\'',
            'error_handling': r'try:.*?except.*?:|catch\s*\(.*?\)',
        }

        self.conversation_patterns = {
            'user_queries': r'^User:.*?(?=\n(?:Assistant|User|\Z))',
            'assistant_responses': r'^Assistant:.*?(?=\n(?:User|Assistant|\Z))',
            'tool_calls': r'Tool:.*?(?=\n(?:User|Assistant|Tool|\Z))',
            'system_messages': r'System:.*?(?=\n(?:User|Assistant|System|\Z))',
        }

        # Semantic importance indicators
        self.importance_indicators = {
            'high': ['error', 'exception', 'critical', 'important', 'warning', 'TODO', 'FIXME', 'BUG'],
            'medium': ['note', 'info', 'debug', 'trace', 'function', 'class', 'method'],
            'low': ['comment', 'example', 'test', 'sample', 'demo']
        }

        from collections import OrderedDict
        self._cache_lock = asyncio.Lock()
        self._cache_ttl_seconds = 1800  # 30 min
        self._cache_max_items = 256
        self.optimization_cache: "OrderedDict[str, tuple[float, OptimizationResult]]" = OrderedDict()

    async def optimize_content_comprehensive(self, content: str, content_type: ContentType,
                                           target_size: Optional[int] = None,
                                           optimization_level: str = "balanced") -> OptimizationResult:
        """Comprehensive content optimization using multiple techniques"""

        start_time = datetime.now()

        # Generate content hash for caching
        content_hash = hashlib.md5(content.encode()).hexdigest()
        cache_key = f"{content_hash}_{content_type.value}_{target_size}_{optimization_level}"

        async with self._cache_lock:
            now = datetime.now().timestamp()
            if cache_key in self.optimization_cache:
                ts, result = self.optimization_cache[cache_key]
                if now - ts <= self._cache_ttl_seconds:
                    # refresh LRU
                    self.optimization_cache.move_to_end(cache_key)
                    return result

        # Multi-stage optimization pipeline
        optimized = content
        optimization_metadata = {
            'stages_applied': [],
            'compression_history': [],
            'quality_metrics': {}
        }

        # Stage 1: Semantic chunking and analysis
        chunks = await self._semantic_chunking(optimized, content_type)
        optimization_metadata['stages_applied'].append('semantic_chunking')
        optimization_metadata['chunk_count'] = len(chunks)

        # Stage 2: Importance-based filtering
        filtered_chunks = self._filter_by_importance(chunks, optimization_level)
        optimization_metadata['stages_applied'].append('importance_filtering')
        optimization_metadata['chunks_retained'] = len(filtered_chunks)

        # Stage 3: Context-aware compression
        if target_size:
            compressed_chunks = await self._compress_contextually(filtered_chunks, target_size, content_type)
            optimization_metadata['stages_applied'].append('contextual_compression')
        else:
            compressed_chunks = filtered_chunks

        # Stage 4: Semantic reconstruction
        optimized = self._reconstruct_semantically(compressed_chunks, content_type)
        optimization_metadata['stages_applied'].append('semantic_reconstruction')

        # Stage 5: Quality assessment
        quality_score = self._assess_optimization_quality(content, optimized, content_type)
        optimization_metadata['quality_metrics']['final_score'] = quality_score

        # Calculate metrics
        compression_ratio = len(optimized) / len(content) if content else 1.0
        processing_time = (datetime.now() - start_time).total_seconds()

        result = OptimizationResult(
            original_content=content,
            optimized_content=optimized,
            optimization_type=OptimizationType.CONTEXT_COMPRESSION,
            compression_ratio=compression_ratio,
            quality_score=quality_score,
            metadata=optimization_metadata,
            processing_time=processing_time
        )

        # Cache the result
        async with self._cache_lock:
            self.optimization_cache[cache_key] = (datetime.now().timestamp(), result)
            self.optimization_cache.move_to_end(cache_key)
            while len(self.optimization_cache) > self._cache_max_items:
                self.optimization_cache.popitem(last=False)
        return result

    async def _semantic_chunking(self, content: str, content_type: ContentType) -> List[SemanticChunk]:
        """Break content into semantically coherent chunks"""
        chunks = []

        if content_type == ContentType.CODE:
            chunks = await self._chunk_code_semantically(content)
        elif content_type == ContentType.CONVERSATION:
            chunks = await self._chunk_conversation_semantically(content)
        elif content_type == ContentType.DOCUMENTATION:
            chunks = await self._chunk_documentation_semantically(content)
        else:
            # Generic chunking for other content types
            chunks = await self._chunk_generic_semantically(content)

        # Enhance chunks with importance scoring
        for chunk in chunks:
            chunk.importance_score = self._calculate_importance_score(chunk.content, content_type)
            chunk.token_estimate = self._estimate_tokens(chunk.content)

        return chunks

    async def _chunk_code_semantically(self, code: str) -> List[SemanticChunk]:
        """Chunk code into semantically meaningful units"""
        chunks = []

        # Extract function/class definitions
        for pattern_name, pattern in self.code_patterns.items():
            matches = re.finditer(pattern, code, re.MULTILINE | re.DOTALL)
            for match in matches:
                chunk = SemanticChunk(
                    content=match.group(),
                    chunk_type=ContentType.CODE,
                    semantic_tags=[pattern_name]
                )

                # Add context dependencies
                if pattern_name == 'function_definitions':
                    # Find imports this function might depend on
                    func_content = match.group()
                    imports = re.findall(r'(?:import|from)\s+([\w\.]+)', code)
                    used_imports = [imp for imp in imports if imp in func_content]
                    chunk.context_dependencies = used_imports

                chunks.append(chunk)

        # If no semantic patterns found, fall back to line-based chunking
        if not chunks:
            lines = code.split('\n')
            current_chunk = []
            for line in lines:
                current_chunk.append(line)
                if len(current_chunk) >= 10:  # Arbitrary chunk size
                    chunks.append(SemanticChunk(
                        content='\n'.join(current_chunk),
                        chunk_type=ContentType.CODE
                    ))
                    current_chunk = []

            if current_chunk:
                chunks.append(SemanticChunk(
                    content='\n'.join(current_chunk),
                    chunk_type=ContentType.CODE
                ))

        return chunks

    async def _chunk_conversation_semantically(self, conversation: str) -> List[SemanticChunk]:
        """Chunk conversation into semantic units (exchanges, tool calls, etc.)"""
        chunks = []

        for pattern_name, pattern in self.conversation_patterns.items():
            matches = re.finditer(pattern, conversation, re.MULTILINE | re.DOTALL)
            for match in matches:
                chunk = SemanticChunk(
                    content=match.group(),
                    chunk_type=ContentType.CONVERSATION,
                    semantic_tags=[pattern_name]
                )

                # Tool calls have high importance
                if pattern_name == 'tool_calls':
                    chunk.importance_score = 0.9

                chunks.append(chunk)

        return chunks

    async def _chunk_documentation_semantically(self, doc: str) -> List[SemanticChunk]:
        """Chunk documentation into semantic sections"""
        chunks = []

        # Split by headers
        sections = re.split(r'\n#{1,6}\s+', doc)
        for section in sections:
            if section.strip():
                chunk = SemanticChunk(
                    content=section.strip(),
                    chunk_type=ContentType.DOCUMENTATION,
                    semantic_tags=['section']
                )
                chunks.append(chunk)

        return chunks

    async def _chunk_generic_semantically(self, content: str) -> List[SemanticChunk]:
        """Generic semantic chunking for other content types"""
        chunks = []

        # Split by paragraphs or logical breaks
        paragraphs = re.split(r'\n\s*\n', content)
        for para in paragraphs:
            if para.strip():
                chunk = SemanticChunk(
                    content=para.strip(),
                    chunk_type=ContentType.SYSTEM_OUTPUT,
                    semantic_tags=['paragraph']
                )
                chunks.append(chunk)

        return chunks

    def _calculate_importance_score(self, content: str, content_type: ContentType) -> float:
        """Calculate importance score for content chunk"""
        content_lower = content.lower()
        score = 0.5  # Base score

        # Check for importance indicators
        for level, indicators in self.importance_indicators.items():
            for indicator in indicators:
                if indicator in content_lower:
                    if level == 'high':
                        score += 0.3
                    elif level == 'medium':
                        score += 0.2
                    elif level == 'low':
                        score += 0.1

        # Content type specific scoring
        if content_type == ContentType.CODE:
            # Function/class definitions are more important
            if re.search(r'(?:def|class|function)', content_lower):
                score += 0.2
            # Error handling is important
            if re.search(r'(?:try|except|catch|error)', content_lower):
                score += 0.2

        elif content_type == ContentType.CONVERSATION:
            # User queries are generally important
            if content.startswith('User:'):
                score += 0.2
            # Tool calls are very important
            if content.startswith('Tool:') or 'tool' in content_lower:
                score += 0.3

        return min(score, 1.0)  # Cap at 1.0

    def _estimate_tokens(self, content: str) -> int:
        """Estimate token count for content"""
        # Rough estimation: ~4 characters per token
        return len(content) // 4

    def _filter_by_importance(self, chunks: List[SemanticChunk], optimization_level: str) -> List[SemanticChunk]:
        """Filter chunks based on importance and optimization level"""
        thresholds = {
            'aggressive': 0.7,
            'balanced': 0.4,
            'conservative': 0.2
        }

        threshold = thresholds.get(optimization_level, 0.4)
        filtered = [chunk for chunk in chunks if chunk.importance_score >= threshold]

        # Always keep at least some content
        if len(filtered) < len(chunks) * 0.3:
            # Sort by importance and keep top 30%
            sorted_chunks = sorted(chunks, key=lambda x: x.importance_score, reverse=True)
            keep_count = max(1, int(len(chunks) * 0.3))
            filtered = sorted_chunks[:keep_count]

        return filtered

    async def _compress_contextually(self, chunks: List[SemanticChunk], target_size: int,
                                    content_type: ContentType) -> List[SemanticChunk]:
        """Apply contextual compression to meet target size"""
        current_size = sum(len(chunk.content) for chunk in chunks)

        if current_size <= target_size:
            return chunks

        # Calculate compression ratio needed
        compression_ratio = target_size / current_size

        compressed_chunks = []
        for chunk in chunks:
            target_chunk_size = int(len(chunk.content) * compression_ratio)

            if target_chunk_size < len(chunk.content):
                compressed_content = await self._compress_chunk_intelligently(
                    chunk.content, target_chunk_size, chunk.chunk_type
                )
                chunk.content = compressed_content

            compressed_chunks.append(chunk)

        return compressed_chunks

    async def _compress_chunk_intelligently(self, content: str, target_size: int,
                                          chunk_type: ContentType) -> str:
        """Intelligently compress a single chunk"""
        if len(content) <= target_size:
            return content

        if chunk_type == ContentType.CODE:
            # For code, preserve structure and remove comments first
            lines = content.split('\n')

            # Remove comments and empty lines first
            compressed_lines = []
            for line in lines:
                stripped = line.strip()
                if stripped and not stripped.startswith('#') and not stripped.startswith('//'):
                    compressed_lines.append(line)

            compressed = '\n'.join(compressed_lines)

            # If still too large, use substring with ellipsis (middle-ellipsis for code)
            if len(compressed) > target_size:
                keep = max(16, (target_size - 5) // 2)
                compressed = compressed[:keep] + ' ... ' + compressed[-keep:]

        else:
            # For other content, use smart truncation
            if target_size > 50:
                # Keep beginning and end, add ellipsis in middle
                keep_size = (target_size - 5) // 2
                compressed = content[:keep_size] + ' ... ' + content[-keep_size:]
            else:
                # Simple truncation
                compressed = content[:target_size-3] + '...'

        return compressed

    def _reconstruct_semantically(self, chunks: List[SemanticChunk], content_type: ContentType) -> str:
        """Reconstruct content from chunks while maintaining semantic coherence"""

        # Sort chunks by importance and dependencies
        sorted_chunks = self._sort_chunks_for_reconstruction(chunks)

        # Add appropriate separators based on content type
        separators = {
            ContentType.CODE: '\n\n',
            ContentType.CONVERSATION: '\n',
            ContentType.DOCUMENTATION: '\n\n',
            ContentType.SYSTEM_OUTPUT: '\n'
        }

        separator = separators.get(content_type, '\n')

        # Reconstruct with context preservation
        reconstructed_parts = []
        for chunk in sorted_chunks:
            # Add context hints if needed
            if chunk.context_dependencies and content_type == ContentType.CODE:
                context_hint = f"# Depends on: {', '.join(chunk.context_dependencies)}\n"
                reconstructed_parts.append(context_hint + chunk.content)
            else:
                reconstructed_parts.append(chunk.content)

        return separator.join(reconstructed_parts)

    def _sort_chunks_for_reconstruction(self, chunks: List[SemanticChunk]) -> List[SemanticChunk]:
        """Sort chunks for optimal reconstruction"""
        # Sort by importance (descending) and then by dependencies
        return sorted(chunks, key=lambda x: (-x.importance_score, len(x.context_dependencies)))

    def _assess_optimization_quality(self, original: str, optimized: str, content_type: ContentType) -> float:
        """Assess the quality of optimization"""
        if not original:
            return 0.0

        # Basic metrics
        compression_ratio = len(optimized) / len(original)

        # Penalize extreme compression
        compression_penalty = 0 if compression_ratio > 0.3 else (0.3 - compression_ratio) * 2

        # Content-specific quality metrics
        content_quality = self._assess_content_quality(original, optimized, content_type)

        # Information preservation estimate
        info_preservation = self._estimate_information_preservation(original, optimized)

        # Combined score
        quality = (
            content_quality * self.optimization_weights['semantic_coherence'] +
            info_preservation * self.optimization_weights['information_density'] +
            (1 - compression_penalty) * self.optimization_weights['token_efficiency'] +
            0.8 * self.optimization_weights['context_relevance']  # Assume good relevance
        )

        return max(0.0, min(1.0, quality))

    def _assess_content_quality(self, original: str, optimized: str, content_type: ContentType) -> float:
        """Assess content-specific quality preservation"""

        if content_type == ContentType.CODE:
            # Check if key code structures are preserved
            original_funcs = len(re.findall(r'def\s+\w+', original))
            optimized_funcs = len(re.findall(r'def\s+\w+', optimized))
            structure_preservation = optimized_funcs / max(1, original_funcs)

            # Check for syntax integrity (basic)
            has_syntax_errors = '...' in optimized and not self._is_valid_truncation(optimized)
            syntax_score = 0.5 if has_syntax_errors else 1.0

            return (structure_preservation + syntax_score) / 2

        elif content_type == ContentType.CONVERSATION:
            # Check if conversation flow is preserved
            original_exchanges = len(re.findall(r'(?:User:|Assistant:)', original))
            optimized_exchanges = len(re.findall(r'(?:User:|Assistant:)', optimized))
            flow_preservation = optimized_exchanges / max(1, original_exchanges)

            return flow_preservation

        else:
            # Generic quality assessment
            # Check if key sentences/concepts are preserved
            original_sentences = len(re.findall(r'\.', original))
            optimized_sentences = len(re.findall(r'\.', optimized))
            sentence_preservation = optimized_sentences / max(1, original_sentences)

            return sentence_preservation

    def _estimate_information_preservation(self, original: str, optimized: str) -> float:
        """Estimate how much information is preserved"""
        # Simple heuristic: character overlap and key term preservation

        # Extract key terms (words longer than 3 characters)
        original_terms = set(re.findall(r'\b\w{4,}\b', original.lower()))
        optimized_terms = set(re.findall(r'\b\w{4,}\b', optimized.lower()))

        if not original_terms:
            return 1.0

        term_overlap = len(original_terms & optimized_terms) / len(original_terms)

        # Factor in length preservation
        length_factor = min(1.0, len(optimized) / len(original))

        return (term_overlap + length_factor) / 2

    def _is_valid_truncation(self, content: str) -> bool:
        """Check if truncated content maintains basic validity"""
        # Basic checks for code
        open_brackets = content.count('(') + content.count('[') + content.count('{')
        close_brackets = content.count(')') + content.count(']') + content.count('}')

        # Allow some imbalance for truncated content
        return abs(open_brackets - close_brackets) <= 2

    async def optimize_query_enhancement(self, query: str, context: str) -> OptimizationResult:
        """Enhance user queries for better processing"""
        start_time = datetime.now()

        enhanced_query = query
        metadata = {'enhancements_applied': []}

        # Add context clues if query is ambiguous
        if len(query.split()) < 3:
            context_clues = self._extract_context_clues(context)
            if context_clues:
                enhanced_query = f"{query} (Context: {context_clues})"
                metadata['enhancements_applied'].append('context_augmentation')

        # Expand abbreviations and technical terms
        expanded_query = self._expand_technical_terms(enhanced_query)
        if expanded_query != enhanced_query:
            enhanced_query = expanded_query
            metadata['enhancements_applied'].append('term_expansion')

        # Add intent markers for better routing
        intent_enhanced = self._add_intent_markers(enhanced_query)
        if intent_enhanced != enhanced_query:
            enhanced_query = intent_enhanced
            metadata['enhancements_applied'].append('intent_enhancement')

        processing_time = (datetime.now() - start_time).total_seconds()

        return OptimizationResult(
            original_content=query,
            optimized_content=enhanced_query,
            optimization_type=OptimizationType.QUERY_ENHANCEMENT,
            compression_ratio=len(enhanced_query) / len(query) if query else 1.0,
            quality_score=1.0,  # Query enhancement typically improves quality
            metadata=metadata,
            processing_time=processing_time
        )

    def _extract_context_clues(self, context: str) -> str:
        """Extract relevant context clues from conversation history"""
        # Look for recent file mentions, tool usage, or technical topics
        clues = []

        # File mentions
        file_matches = re.findall(r'\b\w+\.\w+\b', context)
        if file_matches:
            clues.append(f"files: {', '.join(file_matches[-3:])}")  # Last 3 files

        # Tool usage
        tool_matches = re.findall(r'Tool: (\w+)', context)
        if tool_matches:
            clues.append(f"tools: {', '.join(set(tool_matches[-3:]))}")

        # Technical terms
        tech_terms = re.findall(r'\b(?:function|class|method|variable|error|bug|feature)\b', context.lower())
        if tech_terms:
            clues.append(f"topics: {', '.join(set(tech_terms[-3:]))}")

        return '; '.join(clues)

    def _expand_technical_terms(self, query: str) -> str:
        """Expand common technical abbreviations"""
        expansions = {
            'fn': 'function',
            'var': 'variable',
            'func': 'function',
            'auth': 'authentication',
            'config': 'configuration',
            'db': 'database',
            'api': 'application programming interface',
            'ui': 'user interface',
            'ux': 'user experience'
        }

        words = query.split()
        expanded_words = []

        for word in words:
            clean_word = word.lower().strip('.,!?')
            if clean_word in expansions:
                expanded_words.append(word.replace(clean_word, expansions[clean_word]))
            else:
                expanded_words.append(word)

        return ' '.join(expanded_words)

    def _add_intent_markers(self, query: str) -> str:
        """Add intent markers to help with routing"""
        query_lower = query.lower()

        # Code-related intent markers
        code_indicators = ['function', 'class', 'method', 'code', 'script', 'program']
        if any(indicator in query_lower for indicator in code_indicators):
            return f"[INTENT:CODE] {query}"

        # File operation intent markers
        file_indicators = ['file', 'read', 'write', 'edit', 'save', 'open']
        if any(indicator in query_lower for indicator in file_indicators):
            return f"[INTENT:FILE] {query}"

        # Search intent markers
        search_indicators = ['find', 'search', 'look', 'locate', 'grep']
        if any(indicator in query_lower for indicator in search_indicators):
            return f"[INTENT:SEARCH] {query}"

        # Analysis intent markers
        analysis_indicators = ['analyze', 'explain', 'understand', 'review', 'check']
        if any(indicator in query_lower for indicator in analysis_indicators):
            return f"[INTENT:ANALYSIS] {query}"

        return query

    def get_optimization_statistics(self) -> Dict[str, Any]:
        """Get comprehensive optimization statistics"""
        if not self.optimization_cache:
            return {"message": "No optimization history available"}

        results = list(self.optimization_cache.values())

        stats = {
            'total_optimizations': len(results),
            'average_compression_ratio': sum(r.compression_ratio for r in results) / len(results),
            'average_quality_score': sum(r.quality_score for r in results) / len(results),
            'average_processing_time': sum(r.processing_time for r in results) / len(results),
            'optimization_types': {},
            'content_types_processed': {},
            'cache_hit_efficiency': len(results) / (len(results) + 100)  # Assuming some cache hits
        }

        # Break down by optimization type
        for result in results:
            opt_type = result.optimization_type.value
            if opt_type not in stats['optimization_types']:
                stats['optimization_types'][opt_type] = {
                    'count': 0,
                    'avg_compression': 0,
                    'avg_quality': 0
                }

            stats['optimization_types'][opt_type]['count'] += 1
            stats['optimization_types'][opt_type]['avg_compression'] += result.compression_ratio
            stats['optimization_types'][opt_type]['avg_quality'] += result.quality_score

        # Calculate averages for each type
        for opt_type, data in stats['optimization_types'].items():
            count = data['count']
            data['avg_compression'] /= count
            data['avg_quality'] /= count

        return stats